class Solution {
public:
    int minDays(int n) {
        if (n == 1) return 1;
        if (n == 2) return 2;
        if (n % 3 == 0) return n / 3;
        if (n % 2 == 0) return 1 + minDays(n / 2);
        return 1 + minDays(n - 1);
    }
};
```
